 34→const normalizeInteractionFlag = (value) => {
 35→    if(typeof value === 'boolean') return value;
 36→    if(typeof value === 'string'){
 37→        const normalized = value.trim().toLowerCase();
 38→        if(normalized === 'true') return true;
 39→        if(normalized === 'false') return false;
 40→    }
 41→    if(typeof value === 'number'){
 42→        return value === 1;
 43→    }
 44→    return Boolean(value);
 45→};
 46→
 47→const normalizeCount = (value) => {
 48→    const number = Number(value);
 49→    if(!Number.isFinite(number) || number < 0){
 50→        return 0;
 51→    }
 52→    return number;
 53→};
 54→
 55→const getNextToggleCount = (isActive, currentCount) => {
 56→    return isActive
 57→        ? Math.max(0, currentCount - 1)
 58→        : currentCount + 1;
 59→};
 60→
 61→const ContentView = () => {
 62→    const navigate = useNavigate();
 63→    const [showBackButton, setShowBackButton] = useState(true);
 64→    const { session, user, openAuthModal } = useAuth();
 65→
 66→    const timeOutRef = useRef();
 67→    const timeOutRefBookmark = useRef();
 68→    const bookmarkInFlightRef = useRef(false);
 69→
 70→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 71→    const [userReaction, setUserReaction] = useState(null);
 72→    const [reactionCount, setReactionCount] = useState(0);
 73→    const [isBookmarked, setIsBookmarked] = useState(false);
 74→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 75→
 76→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 77→    const [showRepostModal, setShowRepostModal] = useState(false);
 78→    const [showShareMenu, setShowShareMenu] = useState(false);
 79→
 80→    const contentRef = useRef();
 81→
 82→    const theme = {
 83→        paragraph: 'editor-paragraph',
 84→        heading: {
 85→            h1: 'editor-heading-h1',
 86→            h2: 'editor-heading-h2',
 87→            h3: 'editor-heading-h3',
 88→        },
 89→        quote: 'editor-quote',
 90→        text: {
 91→            bold: 'editor-text-bold',
 92→            italic: 'editor-text-italic',
 93→            underline: 'editor-text-underline',
 94→        }
 95→    }
 96→
 97→    const location = useLocation();
 98→    const { journalId } = useParams();
 99→    const statePostData = location.state;
100→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType || !statePostData?.content);
101→
102→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
103→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
104→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2], { includeRepostContent: false }),
105→        enabled: shouldFetchPost,
106→        staleTime: 1000 * 60 * 5,
107→        refetchOnWindowFocus: false,
108→    });
109→
110→    const postData = useMemo(() => {
111→        const journal = fetchedJournalData?.journal;
112→        if(journal){
113→            const postType = journal?.post_type || 'text';
114→            const parsedContent = ParseContent(journal?.content);
115→            const wholeText = parsedContent?.wholeText || '';
116→
117→            return {
118→                postType: postType,
119→                content: journal?.content,
120→                wholeText: wholeText,
121→                title: journal?.title,
122→                userId: journal?.users?.id || journal?.user_id,
123→                name: journal?.users?.name,
124→                avatar: journal?.users?.image_url,
125→                created_at: journal?.created_at,
126→                journalId: journal?.id,
127→                isLiked: journal?.has_liked,
128→                commentsCount: journal?.comment_count?.[0]?.count || 0,
129→                isBookmarked: journal?.has_bookmarked,
130→                likesCount: journal?.like_count?.[0]?.count || 0,
131→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
132→                badge: journal?.users?.badge,
133→                isRepost: journal?.is_repost === true,
134→                repostCaption: journal?.repost_caption || '',
135→                repostSource: journal?.repost_source || null,
136→                userReaction: journal?.user_reaction || null,
137→                reactionCount: journal?.reaction_count?.[0]?.count || 0
138→            };
139→        }
140→
141→        if(!statePostData){
142→            return null;
143→        }
144→
145→        const inferredPostType = statePostData?.postType || 'text';
146→        const parsedContent = ParseContent(statePostData?.content);
147→
148→        return {
149→            postType: inferredPostType,
150→            content: statePostData?.content,
151→            wholeText: statePostData?.wholeText || parsedContent?.wholeText || '',
152→            title: statePostData?.title,
153→            userId: statePostData?.userId,
154→            name: statePostData?.name,
155→            avatar: statePostData?.avatar,
156→            created_at: statePostData?.created_at,
157→            journalId: statePostData?.journalId,
158→            isLiked: statePostData?.isLiked,
159→            commentsCount: statePostData?.commentsCount || 0,
160→            isBookmarked: statePostData?.isBookmarked,
161→            likesCount: statePostData?.likesCount || 0,
162→            bookmarksCount: statePostData?.bookmarksCount || 0,
163→            badge: statePostData?.badge,
164→            isRepost: statePostData?.isRepost === true,
165→            repostCaption: statePostData?.repostCaption || '',
166→            repostSource: statePostData?.repostSource || null,
167→            userReaction: statePostData?.userReaction || null,
168→            reactionCount: statePostData?.reactionCount || 0
169→        };
170→    }, [fetchedJournalData, statePostData]);
171→
172→    usePostSeo(postData);
173→
174→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
175→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
176→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
177→        staleTime: 1000 * 60 * 60,
178→        gcTime: 1000 * 60 * 60,
179→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
180→    });
181→
182→    const handleclickUserProfile = handleClickProfile(navigate);
183→    const viewContent = handleCLickContent(navigate);
184→
185→    const mutateViews = useAddViewsMutation(session);
186→    const mutationReaction = useReactionMutation(session, user?.userData?.[0]?.id);
187→
188→    const handleReaction = (e, journalId, receiverId, reactionType) => {
189→        e.stopPropagation();
190→        if (!session) { openAuthModal?.(); return; }
191→
192→        const wasReacted = userReaction;
193→        if (wasReacted === reactionType) {
194→            setUserReaction(null);
195→            setReactionCount((c) => Math.max(c - 1, 0));
196→        } else if (wasReacted) {
197→            setUserReaction(reactionType);
198→        } else {
199→            setUserReaction(reactionType);
200→            setReactionCount((c) => c + 1);
201→        }
202→        mutationReaction.mutate({ journalId, receiverId, reactionType });
203→    };
204→
205→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
206→    const handleClickBookmark = async (e, journalId) => {
207→        e.stopPropagation();
208→        if(bookmarkInFlightRef.current){
209→            return;
210→        }
211→        if(!session){
212→            openAuthModal?.();
213→            return;
214→        }
215→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
216→        bookmarkInFlightRef.current = true;
217→        setIsBookmarked(!wasBookmarked);
218→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
219→        let response = null;
220→        try {
221→            response = await mutationBookmark.mutateAsync({ journalId });
222→        } finally {
223→            bookmarkInFlightRef.current = false;
224→        }
225→        
226→        if(timeOutRefBookmark.current){
227→            clearTimeout(timeOutRefBookmark.current);
228→        }
229→        if (response?.message === 'success') {
230→            setBookmarkedMessage('Post was added to your Bookmarks'); 
231→        } else if(response?.message === 'deleted'){
232→            setBookmarkedMessage('Post was removed from your Bookmarks');
233→        }
234→            
235→        timeOutRefBookmark.current = setTimeout(() => {
236→            setBookmarkedMessage('');
237→        }, 1500);
238→
239→    }
240→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
241→
242→    const mutationFollow = useFollowMutation(session);
243→    const handleClickFollow = async (e, followingId, followerId) => {
244→        e.stopPropagation();
245→        if(!session) return openAuthModal();
246→        mutationFollow.mutate({ followingId, followerId });
247→    }
248→    const debounceClickFollow = debounce(handleClickFollow, 100);
249→
250→    const handleBackLocation = (e) => {
251→        e.stopPropagation();
252→        window.history.back();
253→    }
254→
255→    const hanldeClickComments = (e) => {
256→        e.stopPropagation();
257→        if(!session) return openAuthModal();
258→        setShowCommentsContainer(true);
259→    }
260→
261→    const handleCLoseComments = () => {
262→        setShowCommentsContainer(false);
263→    }
264→
265→    useEffect(() => {
266→        if (!postData) return;
267→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
268→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
269→        setUserReaction(postData?.userReaction || null);
270→        setReactionCount(normalizeCount(postData?.reactionCount));
271→    }, [postData?.bookmarksCount, postData?.isBookmarked, postData?.userReaction, postData?.reactionCount]);
272→
273→    useEffect(() => {
274→        const hideBackBttn = () => {
275→            setShowBackButton(false);
276→            if (timeOutRef.current) {
277→                clearTimeout(timeOutRef.current);
278→            }
279→            timeOutRef.current = setTimeout(() => {
280→                setShowBackButton(true);
281→            }, 300);
282→        }
283→
284→        document.addEventListener('scroll', hideBackBttn, true);
285→        return () => {
286→            if (timeOutRef.current) {
287→                clearTimeout(timeOutRef.current);
288→            }
289→            document.removeEventListener('scroll', hideBackBttn, true);
290→        }
291→    }, []);
292→
293→    if (isLoadingJournalById || isLoadingFollows) {
294→        return (
295→            <div className="cv-loading">
296→                <MoonLoader loading={isLoadingJournalById || isLoadingFollows} color="var(--loader-color)" size={25} />
297→            </div>
298→        )
299→    }
300→
301→    if (!postData) {
302→        return (
303→            <div className="cv-loading">
304→                <p>Post is unavailable.</p>
305→                <button onClick={handleBackLocation} className="cv-back-btn" style={{ marginTop: "12px" }}>
306→                    Go back
307→                </button>
308→            </div>
309→        )
310→    }
311→
312→    return (
313→        <>
314→            {showCommentsContainer && (
315→                <AnimatePresence>
316→                    <CommentSection onclose={handleCLoseComments} postId={postData?.journalId} receiverId={postData?.userId} />
317→                </AnimatePresence>
318→            )}
319→
320→            <div ref={contentRef} className="cv-container">
321→                {/* Back header */}
322→                <AnimatePresence>
323→                    {showBackButton && (
324→                        <motion.div
325→                            className="cv-header"
326→                            initial={{ opacity: 0 }}
327→                            animate={{ opacity: 1, transition: { duration: 0.15 } }}
328→                            exit={{ opacity: 0, transition: { duration: 0.15 } }}
329→                        >
330→                            <button onClick={handleBackLocation} className="cv-back-btn">
331→                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 -960 960 960">
332→                                    <path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z" />
333→                                </svg>
334→                            </button>
335→                            <p className="cv-header-label">Post</p>
336→                        </motion.div>
337→                    )}
338→                </AnimatePresence>
339→
340→                <article className="cv-article">
341→                    {postData?.isRepost ? (
342→                        <>
343→                            {/* ── Repost view: quote on top, original post nested below ── */}
344→
345→                            {/* Reposter quote section */}
346→                            <div className="cv-repost-quote-section">
347→                                <div className="cv-repost-badge">
348→                                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="var(--text-faint)">
349→                                        <path d="M7 7h10l-1.293-1.293a1 1 0 0 1 1.414-1.414l3 3a1 1 0 0 1 0 1.414l-3 3a1 1 0 0 1-1.414-1.414L17 9H7a1 1 0 0 1-1-1V5a1 1 0 0 1 2 0v2zm10 10H7l1.293 1.293a1 1 0 0 1-1.414 1.414l-3-3a1 1 0 0 1 0-1.414l3-3a1 1 0 1 1 1.414 1.414L7 15h10a1 1 0 0 1 1 1v3a1 1 0 0 1-2 0v-2z"/>
350→                                    </svg>
351→                                    <span
352→                                        onClick={(e) => handleclickUserProfile(e, user?.userData?.[0]?.id, postData?.userId)}
353→                                        className="cv-repost-badge-name"
354→                                    >
355→                                        {postData?.name}
356→                                    </span>
357→                                    <VerifiedBadge badge={postData?.badge} size={14} />
358→                                    <span className="cv-repost-badge-label">reposted</span>
359→                                    <span className="cv-repost-badge-date">
360→                                        {new Date(postData?.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
361→                                    </span>
362→                                </div>
363→
364→                                {postData.repostCaption && (
365→                                    <p className="cv-repost-caption">{postData.repostCaption}</p>
366→                                )}
367→                            </div>
368→
369→                            {/* Original post nested below */}
370→                            {postData.repostSource ? (
371→                                <div
372→                                    className="cv-repost-embedded"
